import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Поширені питання","description":"Поширені запитання для гравців і адміністраторів серверів, пов’язані з Fabric.","frontmatter":{"title":"Поширені питання","description":"Поширені запитання для гравців і адміністраторів серверів, пов’язані з Fabric.","search":false,"files":[]},"headers":[],"relativePath":"uk_ua/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/uk_ua/players/faq.md","lastUpdated":1739538073000}`);var a={name:`uk_ua/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Поширені питання <a class="header-anchor" href="#h1" aria-label="Permalink to “Поширені питання”">​</a></h1><p>Є багато запитань, які часто задають, тому ми склали їх список тут.</p><h2 id="загальні-питання" tabindex="-1">Загальні питання <a class="header-anchor" href="#загальні-питання" aria-label="Permalink to “Загальні питання”">​</a></h2><h3 id="які-версіі-minecraft-підтримує-fabric" tabindex="-1">Які версії Minecraft підтримує Fabric? <a class="header-anchor" href="#які-версіі-minecraft-підтримує-fabric" aria-label="Permalink to “Які версії Minecraft підтримує Fabric?”">​</a></h3><p>Офіційно Fabric підтримує всі версії Minecraft починаючи зі снапшоту <code>18w43b</code> та релізу <code>1.14</code> та вище.</p><h3 id="де-я-можу-завантажити-моди-для-fabric" tabindex="-1">Де я можу завантажити моди для Fabric? <a class="header-anchor" href="#де-я-можу-завантажити-моди-для-fabric" aria-label="Permalink to “Де я можу завантажити моди для Fabric?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Ви завжди маєте перевіряти чи моди з надійного джерела. Щоб дізнатися більше, перегляньте інструкцію <a href="./finding-mods">Пошук надійних модів</a>.</p></div><p>Більшість авторів публікують свої моди на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> та <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, але деякі автори викладають їх на свої веб-сайти або інші платформи, такі як репозиторії GitHub.</p><h3 id="де-я-можу-знаити-готові-модпаки-для-fabric" tabindex="-1">Де я можу знайти готові модпаки для Fabric? <a class="header-anchor" href="#де-я-можу-знаити-готові-модпаки-для-fabric" aria-label="Permalink to “Де я можу знайти готові модпаки для Fabric?”">​</a></h3><p>Ви можете знайти готові мод-паки для Fabric на платформах, таких як:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};